import Layout from '../components/Layout';
import AisleBrowser from '../components/AisleBrowser';
import BookList from '../components/BookList';
import { useState } from 'react';

const demoBooks = [
  { id: 1, title: 'Introduction to Algorithms', author: 'Cormen', category: 'CS', isbn: '9780262033848', aisle: 'A', shelf: '1', quantity: 3 },
  { id: 2, title: 'Modern Physics', author: 'Tipler', category: 'Physics', isbn: '9780716783319', aisle: 'B', shelf: '2', quantity: 0 },
];
const aisles = ['A', 'B', 'C'];

export default function Aisles() {
  const [selectedAisle, setSelectedAisle] = useState('A');
  const books = demoBooks.filter(b => b.aisle === selectedAisle);

  return (
    <Layout>
      <AisleBrowser aisles={aisles} onSelectAisle={setSelectedAisle} selectedAisle={selectedAisle} />
      <BookList books={books} />
    </Layout>
  );
}
